#include<bits/stdc++.h>
using namespace std;
const int N = 1e5+5;
struct node{long long x,y;}a[N];
long long n,px[N],py[N],sx[N],sy[N],ans=0x3f3f3f3f3f3f3f3f;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i].x>>a[i].y;
		px[i]=a[i].x+a[i].y,py[i]=a[i].x-a[i].y;
		a[i].x=px[i],a[i].y=py[i];
	}
	sort(px+1,px+n+1);
	sort(py+1,py+n+1);
	for(int i=1;i<=n;i++)
        sx[i]=sx[i-1]+px[i],sy[i]=sy[i-1]+py[i];
	for(int i=1;i<=n;i++){
		int idx=lower_bound(px+1,px+n+1,a[i].x)-px;
		int idy=lower_bound(py+1,py+n+1,a[i].y)-py;
		long long tmp=px[idx]*(idx-1)-sx[idx-1]+sx[n]-sx[idx]-px[idx]*(n-idx);
		tmp+=py[idy]*(idy-1)-sy[idy-1]+sy[n]-sy[idy]-py[idy]*(n-idy);
		ans=min(ans,tmp);
	}
	cout<<ans/2;
	return 0;
}
